import Foundation
import Observation

// MARK: - Clock abstraction (testable time source)

/// Abstracts `Date.now` so tests can inject a fixed point in time.
public protocol ClockProvider: Sendable {
    func now() -> Date
}

public struct SystemClock: ClockProvider {
    public init() {}
    public func now() -> Date { Date() }
}

// MARK: - Store

/// Formats the active Claude account's time-window metrics for the menu bar.
/// Example: `S 48% 2h 13m | W 7% 6d 6h 13m`. Falls back to `"--"` when data is
/// unavailable, malformed, or no active account is found.
@Observable
@MainActor
public final class UsageStore {
    public private(set) var menuBarText: String = "--"
    /// Incremented each time handleNewData is called, whether the data is valid or malformed.
    /// Tests use this as a reliable signal that the store has consumed the latest yielded item.
    public private(set) var dataProcessedCount: Int = 0
    public private(set) var entries: [VendorUsageEntry] = []

    // MARK: Dependencies

    private let fileWatcher: FileWatching
    private let clock: ClockProvider
    private let logger: FileLogger
    private let countdownRefreshSeconds: UInt64

    public static let defaultCountdownRefreshSeconds: UInt64 = 60
    private static let fallbackText = "--"
    private static let targetVendor: Vendor = .claude

    // Latest decoded file kept for countdown refresh without re-reading disk
    private var lastFile: UsagesFile?

    private var watchTask: Task<Void, Never>?
    private var countdownTask: Task<Void, Never>?

    public init(
        fileWatcher: FileWatching,
        clock: ClockProvider = SystemClock(),
        logger: FileLogger = Loggers.app,
        countdownRefreshSeconds: UInt64 = UsageStore.defaultCountdownRefreshSeconds
    ) {
        self.fileWatcher = fileWatcher
        self.clock = clock
        self.logger = logger
        self.countdownRefreshSeconds = countdownRefreshSeconds
    }

    // MARK: Lifecycle

    /// Start watching the file and refreshing the countdown.
    /// Idempotent — calling again is a no-op.
    public func start() {
        guard watchTask == nil else { return }

        let watcher = fileWatcher
        // Self is captured strongly; stop() cancels both tasks to break the cycle
        watchTask = Task { [self] in
            for await data in watcher.changes() {
                guard !Task.isCancelled else { break }
                self.handleNewData(data)
            }
        }

        countdownTask = Task { [self] in
            let refreshNanos = self.countdownRefreshSeconds * 1_000_000_000
            while !Task.isCancelled {
                // CancellationError swallowed intentionally; checked on next loop iteration
                try? await Task.sleep(nanoseconds: refreshNanos)
                guard !Task.isCancelled else { break }
                self.refreshMenuBarText()
            }
        }
    }

    /// Stop all background tasks. Idempotent.
    public func stop() {
        watchTask?.cancel()
        watchTask = nil
        countdownTask?.cancel()
        countdownTask = nil
    }

    // Defensive: cancels tasks when the store is released without an explicit stop() call.
    @MainActor deinit { stop() }

    // MARK: - Processing

    private func handleNewData(_ data: Data) {
        dataProcessedCount += 1
        do {
            let file = try JSONDecoder().decode(UsagesFile.self, from: data)
            lastFile = file
            entries = file.usages
            menuBarText = format(file: file)
        } catch {
            logger.log(.error, "UsageStore: JSON decode failed: \(error)")
            lastFile = nil
            entries = []
            menuBarText = Self.fallbackText
        }
    }

    private func refreshMenuBarText() {
        guard let file = lastFile else { return }
        menuBarText = format(file: file)
    }

    // MARK: - Formatting

    private func format(file: UsagesFile) -> String {
        guard let entry = file.usages.first(where: {
            $0.vendor == Self.targetVendor && $0.isActive
        }) else {
            return Self.fallbackText
        }

        let segments = entry.metrics.compactMap(formatTimeWindowSegment)

        return segments.isEmpty ? Self.fallbackText : segments.joined(separator: " | ")
    }

    private func formatTimeWindowSegment(_ metric: UsageMetric) -> String? {
        if case let .unknown(t) = metric {
            logger.log(.debug, "UsageStore: skipping unknown metric type '\(t)'")
        }
        guard case let .timeWindow(name, resetAt, _, usagePercent) = metric else {
            return nil
        }

        let abbreviation = name.prefix(1).uppercased()
        // A metric with an empty name cannot be abbreviated — skip to avoid a leading space in output
        guard !abbreviation.isEmpty else { return nil }
        let remaining = formatRemainingTime(resetAt: resetAt)
        return "\(abbreviation) \(usagePercent.rawValue)% \(remaining)"
    }

    private func formatRemainingTime(resetAt: ISODate) -> String {
        guard resetAt.date != nil else {
            logger.log(.warning, "UsageStore: invalid ISO8601 resetAt value: \(resetAt.rawValue)")
            return "--"
        }
        return AIUsagesTrackersLib.formatRemainingTime(resetAt: resetAt, now: clock.now())
    }
}

import Foundation
import Testing
@testable import AIUsagesTrackersLib

// MARK: - Test doubles

/// A mock FileWatching that lets tests push arbitrary Data payloads.
/// Implemented as a class so `changes()` can hand out a fresh AsyncStream on each
/// call — required for start/stop/start lifecycle tests where the previous iteration
/// is cancelled before a new watchTask begins consuming again.
final class MockFileWatcher: FileWatching, @unchecked Sendable {
    // Protected by @MainActor in tests; @unchecked Sendable because AsyncStream.Continuation
    // is Sendable and all test access is single-threaded on the main actor.
    private var continuation: AsyncStream<Data>.Continuation?
    /// Buffers sends that arrive before the watch task calls changes(), or after a
    /// cancelled previous cycle. Flushed immediately when changes() is called.
    private var pendingData: [Data] = []

    func changes() -> AsyncStream<Data> {
        // Finish the previous stream (if any) before creating a new one.
        // This prevents a stale task from consuming the new continuation's yields.
        continuation?.finish()
        var cont: AsyncStream<Data>.Continuation!
        let stream = AsyncStream<Data> { cont = $0 }
        continuation = cont
        // Flush sends that arrived before this call (e.g. test called send() before
        // the watch task had a chance to call changes()).
        for data in pendingData { cont.yield(data) }
        pendingData.removeAll()
        return stream
    }

    func send(_ data: Data) {
        guard let cont = continuation else {
            pendingData.append(data)
            return
        }
        // .terminated means the previous cycle's consuming task was cancelled;
        // buffer the data so the next changes() call can deliver it.
        if case .terminated = cont.yield(data) {
            continuation = nil
            pendingData.append(data)
        }
    }

    func finish() { continuation?.finish() }
}

/// A clock fixed at a given date, for deterministic remaining-time formatting.
struct FixedClock: ClockProvider {
    let date: Date
    init(_ date: Date) { self.date = date }
    func now() -> Date { date }
}

/// A clock whose date can be advanced between test steps to simulate time passing.
/// nonisolated(unsafe) — tests drive date changes from @MainActor, single-threaded; no concurrent writes.
@MainActor
final class MutableClock: ClockProvider {
    nonisolated(unsafe) var date: Date
    init(_ date: Date) { self.date = date }
    nonisolated func now() -> Date { date }
}

// MARK: - Async helpers

private struct EventuallyTimeoutError: Error {}

/// Polls `condition` on the main actor at `interval` until it returns true or `timeout` expires.
@MainActor
private func eventually(
    timeout: TimeInterval = 2.0,
    interval: TimeInterval = 0.01,
    _ condition: @MainActor () -> Bool
) async throws {
    let deadline = Date(timeIntervalSinceNow: timeout)
    while true {
        if condition() { return }
        guard Date() < deadline else { throw EventuallyTimeoutError() }
        try await Task.sleep(nanoseconds: UInt64(interval * 1_000_000_000))
    }
}

// MARK: - Helpers

private func makeUsagesJSON(
    vendor: String = "claude",
    account: String = "user@example.com",
    isActive: Bool = true,
    metrics: [[String: Any]] = []
) throws -> Data {
    let entry: [String: Any] = [
        "vendor": vendor,
        "account": account,
        "isActive": isActive,
        "metrics": metrics,
    ]
    let root: [String: Any] = ["usages": [entry]]
    return try JSONSerialization.data(withJSONObject: root)
}

private func timeWindowMetric(
    name: String = "session",
    resetAt: String = "2026-04-17T15:00:00Z",
    windowDurationMinutes: Int = 300,
    usagePercent: Int = 42
) -> [String: Any] {
    [
        "type": "time-window",
        "name": name,
        "resetAt": resetAt,
        "windowDurationMinutes": windowDurationMinutes,
        "usagePercent": usagePercent,
    ]
}

private func payAsYouGoMetric(
    name: String = "monthly",
    currentAmount: Double = 12.50,
    currency: String = "USD"
) -> [String: Any] {
    [
        "type": "pay-as-you-go",
        "name": name,
        "currentAmount": currentAmount,
        "currency": currency,
    ]
}

// MARK: - Tests

@Suite("UsageStore formatting")
struct UsageStoreFormattingTests {

    private static let referenceDate: Date = ISO8601DateFormatter().date(from: "2026-04-17T12:47:00Z")!

    @MainActor
    @Test("default menuBarText is fallback")
    func defaultIsFallback() {
        let watcher = MockFileWatcher()
        let store = UsageStore(fileWatcher: watcher)
        #expect(store.menuBarText == "--")
    }

    @MainActor
    @Test("single time-window metric formats correctly")
    func singleTimeWindow() async throws {
        let watcher = MockFileWatcher()
        let clock = FixedClock(Self.referenceDate)
        let store = UsageStore(fileWatcher: watcher, clock: clock, countdownRefreshSeconds: 999)
        store.start()

        // resetAt is 2h13m in the future from Self.referenceDate
        let data = try makeUsagesJSON(metrics: [
            timeWindowMetric(name: "session", resetAt: "2026-04-17T15:00:00Z", usagePercent: 48),
        ])
        watcher.send(data)
        try await eventually { store.menuBarText == "S 48% 2h 13m" }
        #expect(store.menuBarText == "S 48% 2h 13m")
        store.stop()
    }

    @MainActor
    @Test("multiple time-window metrics joined by pipe")
    func multipleTimeWindows() async throws {
        let watcher = MockFileWatcher()
        let clock = FixedClock(Self.referenceDate)
        let store = UsageStore(fileWatcher: watcher, clock: clock, countdownRefreshSeconds: 999)
        store.start()

        let data = try makeUsagesJSON(metrics: [
            timeWindowMetric(name: "session", resetAt: "2026-04-17T15:00:00Z", usagePercent: 48),
            timeWindowMetric(name: "weekly", resetAt: "2026-04-23T21:00:00Z", usagePercent: 7),
        ])
        watcher.send(data)
        try await eventually { store.menuBarText == "S 48% 2h 13m | W 7% 6d 8h 13m" }
        #expect(store.menuBarText == "S 48% 2h 13m | W 7% 6d 8h 13m")
        store.stop()
    }

    @MainActor
    @Test("pay-as-you-go metrics are ignored")
    func payAsYouGoIgnored() async throws {
        let watcher = MockFileWatcher()
        let clock = FixedClock(Self.referenceDate)
        let store = UsageStore(fileWatcher: watcher, clock: clock, countdownRefreshSeconds: 999)
        store.start()

        let data = try makeUsagesJSON(metrics: [
            payAsYouGoMetric(),
        ])
        watcher.send(data)
        try await eventually { store.dataProcessedCount == 1 }
        // No time-window metrics → fallback
        #expect(store.menuBarText == "--")
        store.stop()
    }

    @MainActor
    @Test("mixed metrics: only time-window rendered")
    func mixedMetrics() async throws {
        let watcher = MockFileWatcher()
        let clock = FixedClock(Self.referenceDate)
        let store = UsageStore(fileWatcher: watcher, clock: clock, countdownRefreshSeconds: 999)
        store.start()

        let data = try makeUsagesJSON(metrics: [
            timeWindowMetric(name: "session", resetAt: "2026-04-17T15:00:00Z", usagePercent: 48),
            payAsYouGoMetric(),
        ])
        watcher.send(data)
        try await eventually { store.menuBarText == "S 48% 2h 13m" }
        #expect(store.menuBarText == "S 48% 2h 13m")
        store.stop()
    }

    @MainActor
    @Test("resetAt in the past shows 0m")
    func resetAtInPast() async throws {
